import Link from "next/link";import { requireUser } from "@/src/lib/auth/session";import { createSupabaseServerClient } from "@/src/lib/supabase/server";
export default async function VendorOpportunitiesPage(){const user=await requireUser();const vendor=user.memberships.find(m=>m.organizationType==="vendor");if(!vendor)return null;const db=await createSupabaseServerClient();const {data:rawData}=await db.from("property_manager_service_requests").select("id,priority,status,problem_description,submitted_at,assigned_at,properties(city_id,cities(name,state_code)),vendor_categories(name)").eq("assigned_vendor_organization_id",vendor.organizationId).order("submitted_at",{ascending:false});const data=rawData??[];const counts={new:data.filter(x=>x.status==="submitted").length,open:data.filter(x=>["submitted","reviewing"].includes(x.status)).length,accepted:data.filter(x=>x.status==="assigned").length,completed:data.filter(x=>x.status==="completed").length};return <div><p className="text-sm font-semibold text-emerald-700">Vendor workspace</p><h1 className="mt-1 text-4xl font-semibold">Opportunities</h1><p className="mt-3 max-w-3xl text-sm text-slate-500">Opportunities are provided based on service category, service area, active membership, profile eligibility, and administrator assignment. Opportunity availability and job awards are not guaranteed.</p><div className="mt-7 grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{Object.entries(counts).map(([label,value])=><div key={label} className="rounded-2xl border border-slate-200 bg-white p-5"><p className="text-xs font-bold capitalize text-slate-500">{label} opportunities</p><p className="mt-3 text-3xl font-bold">{value}</p></div>)}</div>{data.length?<div className="mt-8 grid gap-4">{data.map(item=>{const property=item.properties as unknown as {cities:{name:string;state_code:string}|null}|null;return <Link key={item.id} href={`/vendor/opportunities/${item.id}`} className="rounded-2xl border border-slate-200 bg-white p-5 hover:border-emerald-300"><div className="flex justify-between gap-4"><div><p className="font-bold">{(item.vendor_categories as unknown as {name:string}|null)?.name}</p><p className="mt-2 text-sm text-slate-600">{item.problem_description.slice(0,180)}{item.problem_description.length>180?"…":""}</p><p className="mt-3 text-xs text-slate-500">{property?.cities?`${property.cities.name}, ${property.cities.state_code}`:"Service area"} · Submitted {item.submitted_at?new Date(item.submitted_at).toLocaleDateString():"—"}</p></div><span className="h-fit rounded-full bg-slate-100 px-3 py-1 text-xs font-bold capitalize">{item.priority.replaceAll("_"," ")} · {item.status}</span></div>{item.assigned_at?<p className="mt-3 text-xs text-emerald-700">Assigned {new Date(item.assigned_at).toLocaleDateString()}</p>:null}</Link>})}</div>:<section className="mt-8 rounded-2xl border border-dashed border-slate-300 bg-white p-10 text-center text-sm text-slate-500">No opportunities are assigned to your business right now. New property-manager requests will appear here when matched to your services.</section>}</div>}
